unsigned int fibonacci(unsigned int n) {
    if (n <= 1) return n;
    unsigned int a = 0, b = 1;
    for (unsigned int i = 2; i <= n; i++) {
        unsigned int tmp = a + b;
        a = b;
        b = tmp;
    }
    return b;
}

tests:
